import Vue from 'vue'
import App from './App'
import VueRouter from 'vue-router'
// import VueResource from 'vue-resource'//拿来获取数据,类似于axios
import Routers from './routers'//引入自定义的routers
import axios from 'axios'

//全局配置
axios.defaults.baseURL = 'https://vuedemo-dcdfe.firebaseio.com';

Vue.config.productionTip = false;

// Vue.use(VueResource);
Vue.use(VueRouter);
//创建路由
const router = new VueRouter({
  routes: Routers,
  mode:'history'
})
router.beforeEach((to,from,next) =>{
  if(to.meta.title){
    document.title = to.meta.title
  }
  next();
})
