<template>
  <div id="single-blog">
    <span>博客标题：</span>
    <span class="title">{{blog.title}}</span>
    <p>博客内容：</p>
    <article>{{blog.content}}</article>
    <p>作者：{{blog.author}}</p>
    <p>分类</p>
    <ul>
      <li v-for="category in blog.categories">
        {{category}}
      </li>
    </ul>
    <button @click="deleteSingleBlog()">删除</button>
    <button><router-link :to="'/edit/'+id">编辑</router-link></button>
  </div>
</template>

<script type="text/ecmascript-6">
  import axios from 'axios'
  export default {
    name: 'single-blog',
    data() {
      return {
        id: this.$route.params.id,// 拿到路由id
        blog: {}
      }
    },
    created() {
      // this.$http.get("https://vuedemo-dcdfe.firebaseio.com/posts/" + this.id + ".json")
      axios.get("/posts/" + this.id + ".json")
        .then( (data) => {
          // console.log(data)
          this.blog = data.data
          // this.blog = data.body;
        })
    },
    methods: {
      deleteSingleBlog(){
        // this.$http.delete("https://vuedemo-dcdfe.firebaseio.com/posts/" + this.id + ".json")

        let pd = confirm("确认删除？");
        if (pd) {
          axios.delete("/posts/" + this.id + ".json")
            .then((response)=>{
              this.$router.push({path:'/'})
            })
        }
      }
    }
  }
</script>

<style scoped>
  #single-blog {
    max-width: 960px;
    margin: 0 auto;
    padding: 20px;
    background-color: #eee;
    border: 1px dotted #aaa;
  }
  a{
    text-decoration: none;
    color: white;
  }
  button:nth-of-type(1) {
    /*display: block;*/
    margin: 20px 0;
    background-color: crimson;
    color: white;
    border: 0;
    padding: 14px;
    border-radius: 4px;
    font-size: 18px;
    cursor: pointer;
  }
  button:nth-of-type(2) {
    /*display: block;*/
    margin: 20px 0;
    background-color: #19c0dc;
    color: white;
    border: 0;
    padding: 14px;
    border-radius: 4px;
    font-size: 18px;
    cursor: pointer;
  }
  .title{
    font-size: 18px;
    font-weight: bold;
  }
</style>



