<template>
  <div id="show-blogs" v-theme:column="'wide'">
    <h1>博客总览</h1>
    <input type="text" placeholder="搜索" v-model="search">
    <div class="single-blog" v-for="blog in filteredBlogs">
      <router-link :to="'/blog/'+blog.id">
        <h2 v-rainbow>{{blog.title | to-uppercase}}</h2>
      </router-link>
      <span>{{blog.content | snippet}}</span>
    </div>
  </div>
</template>

<script type="text/ecmascript-6">
  import axios from 'axios'
  export default {
    name: 'show-blogs',
    data() {
      return {
        blogs: [],
        search: ""
      }
    },
    //局部过滤器
    filters: {
      "to-uppercase": function (value) {
        return value.toLowerCase().replace(/( |^)[a-z]/g, (L) => L.toUpperCase());// 首字母大写
      },
      "snippet": function (value) {
        if (value.length > 10) {
          return value.slice(0, 10) + "..."
        } else {
          return value
        }
      }
    },
    //局部自定义指令
    directives: {
      'rainbow': {
        bind(el, binding, vnode) {
          el.style.color = "black";//Math.random().toString(16).slice(2, 8)
        }
      },
      'theme': {
        bind(el, binding, vonde) {
          if (binding.value === 'wide') {
            el.style.maxWidth = "1260px";
          } else if (binding.value === 'narrow') {
            el.style.maxWidth = "560px";
          }
          if (binding.arg === 'column') {
            el.style.backgroundColor = "#6677cc";
            el.style.padding = '20px'
          }
        }
      }
    },
    computed: {
      filteredBlogs: function () {
        return this.blogs.filter((blog) => {
          return blog.title.toLowerCase().match(this.search.toLowerCase())
        })
      }
    },
    created() {
      //https://jsonplaceholder.typicode.com/posts
      // this.$http.get("https://vuedemo-dcdfe.firebaseio.com/posts.json")
      axios.get("/posts.json")
        .then(function (data) {
          // console.log(data.json())
          // return data.json()
          // axios
          // console.log(data.data)
          return data.data;
        })
        .then( (data) => {
          let blogsArray = [];
          for (let key in data) {
            // console.log(key)
            // console.log(data[key])
            data[key].id = key;
            blogsArray.push(data[key])
          }
          // console.log(blogsArray)
          this.blogs = blogsArray;
          console.log(this.blogs)
        })
    }
  }
</script>

<style>
  #show-blogs {
    max-width: 800px;
    margin: 0 auto 30px;
  }

  .single-blog {
    padding: 20px;
    margin: 20px 0;
    box-sizing: border-box;
    background-color: #ccc;
    border: 1px dotted #aaa;
  }

  #show-blogs a {
    color: #444;
    text-decoration: none
  }

  input[type="text"] {
    padding: 8px;
    width: 100%;
    box-sizing: border-box;
    border: 0;
    border-radius: 5px;
  }
</style>



